CREATE VIEW `ads_consume_short_video_consume_view` (`dt` COMMENT "日期", `id` COMMENT "主键", `create_time` COMMENT "创建时间", `account_id` COMMENT "账号id", `coin` COMMENT "当前代币数", `bonus` COMMENT "当前赠币数", `update_time` COMMENT "更新时间", `pre_bonus` COMMENT "充值前赠币", `pre_coin` COMMENT "充值前代币", `epis_id` COMMENT "剧集id", `series_id` COMMENT "剧id", `epis_name` COMMENT "剧集名称", `epis_num` COMMENT "集数", `platform` COMMENT "平台", `gain_bonus` COMMENT "获得的bonus", `gain_coin` COMMENT "获得的coin", `bill_type` COMMENT "充值类型", `consume_type` COMMENT "消费类型,0是代币,1是赠币", `consume_type2` COMMENT "消费类型(解锁方式),0是普通方式代币,1是普通方式赠币,2超前点播代币，3超前点播赠币", `consume_value` COMMENT "消费数量", `region_id` COMMENT "归属区域 id，1：香港，2：北美;", `corever2` COMMENT "当前core")
COMMENT "海外短剧消耗表" AS SELECT `a`.`dt`, `a`.`Id`, `a`.`create_time`, `a`.`account_id`, `a`.`Coin`, `a`.`Bonus`, `a`.`update_time`, `a`.`pre_bonus`, `a`.`pre_coin`, `a`.`epis_id`, `dim`.`b`.`series_id`, `a`.`epis_name`, `a`.`epis_num`, `a`.`Platform`, `a`.`gain_bonus`, `a`.`gain_coin`, `a`.`bill_type`, `a`.`consume_type`, `a`.`consume_type2`, `a`.`consume_value`, `a`.`region_id`, `dim`.`c`.`corever2`
FROM (SELECT `ods`.`a`.`dt`, `ods`.`a`.`Id`, `ods`.`a`.`CreateTime` AS `create_time`, `ods`.`a`.`AccountId` AS `account_id`, `ods`.`a`.`Coin`, `ods`.`a`.`Bonus`, `ods`.`a`.`UpdateTime` AS `update_time`, `ods`.`a`.`PreBonus` AS `pre_bonus`, `ods`.`a`.`PreCoin` AS `pre_coin`, `ods`.`a`.`EpisId` AS `epis_id`, `ods`.`a`.`EpisName` AS `epis_name`, `ods`.`a`.`EpisNum` AS `epis_num`, `ods`.`a`.`Platform`, `ods`.`a`.`GainBonus` AS `gain_bonus`, `ods`.`a`.`GainCoin` AS `gain_coin`, `ods`.`a`.`BillType` AS `bill_type`, 0 AS `consume_type`, `ods`.`a`.`ConsumeType` AS `consume_type2`, `ods`.`a`.`PreCoin` - `ods`.`a`.`Coin` AS `consume_value`, `ods`.`a`.`regionId` AS `region_id`
FROM `ods`.`ods_tidb_short_video_bill` AS `a`
WHERE ((`ods`.`a`.`ConsumeType` IS NOT NULL) AND (`ods`.`a`.`ConsumeType` != '')) AND ((`ods`.`a`.`PreCoin` - `ods`.`a`.`Coin`) > 0) UNION ALL SELECT `ods`.`a`.`dt`, `ods`.`a`.`Id`, `ods`.`a`.`CreateTime` AS `create_time`, `ods`.`a`.`AccountId` AS `account_id`, `ods`.`a`.`Coin`, `ods`.`a`.`Bonus`, `ods`.`a`.`UpdateTime` AS `update_time`, `ods`.`a`.`PreBonus` AS `pre_bonus`, `ods`.`a`.`PreCoin` AS `pre_coin`, `ods`.`a`.`EpisId` AS `epis_id`, `ods`.`a`.`EpisName` AS `epis_name`, `ods`.`a`.`EpisNum` AS `epis_num`, `ods`.`a`.`Platform`, `ods`.`a`.`GainBonus` AS `gain_bonus`, `ods`.`a`.`GainCoin` AS `gain_coin`, `ods`.`a`.`BillType` AS `bill_type`, 1 AS `consume_type`, `ods`.`a`.`ConsumeType` AS `consume_type2`, `ods`.`a`.`PreBonus` - `ods`.`a`.`Bonus` AS `consume_value`, `ods`.`a`.`regionId` AS `region_id`
FROM `ods`.`ods_tidb_short_video_bill` AS `a`
WHERE ((`ods`.`a`.`ConsumeType` IS NOT NULL) AND (`ods`.`a`.`ConsumeType` != '')) AND ((`ods`.`a`.`PreBonus` - `ods`.`a`.`Bonus`) > 0)) `a` LEFT OUTER JOIN `dim`.`dim_short_video_epis_view` AS `b` ON `a`.`epis_id` = `dim`.`b`.`epis_id` LEFT OUTER JOIN `dim`.`dim_short_video_user_accountinfo` AS `c` ON `a`.`account_id` = `dim`.`c`.`user_id`;